+    #[test]
+    fn get_explanation_all_deny_templates() {
+        let deny_ids = [
+            "deny.alt_screen",
+            "deny.command_running",
+            "deny.recent_gap",
+            "deny.rate_limited",
+            "deny.unknown_pane",
+            "deny.permission",
+        ];
+        for id in deny_ids {
+            let tmpl = get_explanation(id);
+            assert!(tmpl.is_some(), "Should find template for '{id}'");
+            assert_eq!(tmpl.unwrap().id, id);
+        }
+    }
